// // This module designs a 16-bit down counter that decrements its value on each clock pulse and resets to zero when the reset signal is deasserted.
module counter_16bit(  
    input clk,  
    input reset,  
    input enable,  
    output reg [15:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 16'b0;  
        end else if (enable) begin  
            count <= count + 1;  
        end  
    end  
endmodule
